import React, { useEffect, useState } from 'react';
import IconButton from '@material-ui/core/IconButton';
import DeleteIcon from '@material-ui/icons/Delete';

function ImageUpload({ imagePreviews, handleImageChange, handleRemoveImage, handleRemoveExistingImage, existingImages }) {
  const [previews, setPreviews] = useState([]);

  useEffect(() => {
    // Uppdatera imagePreviews när existingImages ändras
    setPreviews(existingImages.map(image => ({
      src: `https://nice-special-meadow.glitch.me/images/${image}`,
      alt: `Existing Image`,
    })));
  }, [existingImages]);

  return (
    <div>
      <input
        type="file"
        name="images"
        accept="image/*"
        onChange={handleImageChange}
        multiple
      />
      {/* Loopa igenom befintliga bilder och rendera dem */}
      {previews.map((preview, index) => (
        <div key={index}>
          <img
            src={preview.src}
            alt={preview.alt}
            style={{ maxWidth: '100px', maxHeight: '100px' }}
          />
          <IconButton onClick={() => handleRemoveExistingImage(index)}>
            <DeleteIcon />
          </IconButton>
        </div>
      ))}

      {/* Loopa igenom bildförhandsvisningar och rendera dem */}
      {imagePreviews.map((preview, index) => (
        <div key={index}>
          <img
            src={preview}
            alt={`Preview ${index + 1}`}
            style={{ maxWidth: '100px', maxHeight: '100px' }}
          />
          <IconButton onClick={() => handleRemoveImage(index)}>
            <DeleteIcon />
          </IconButton>
        </div>
      ))}
    </div>
  );
}

export default ImageUpload;
